<script data-cfasync="false" type="text/javascript">
// Financial reports behavior: generate preview, filter transactions, paginate, export, and print reports.
(function(){var txns=<?php echo json_encode($transactions); ?>,filtered=txns.slice(),currentPage=1,school=<?php echo json_encode($school); ?>,accountant=<?php echo json_encode($accountantName); ?>;function byId(id){return document.getElementById(id)}function money(v){return '₦'+Number(v||0).toLocaleString()}function statusClass(s){return s.toLowerCase()}function csvEscape(v){return '"'+String(v).replace(/"/g,'""')+'"'}function rowsForExport(rows){return [['Date','Transaction ID','Description','Category','Amount','Type','Status']].concat(rows.map(function(r){return[r.date,r.id,r.description,r.category,r.amount,r.type,r.status]}))}function downloadCsv(rows,name){var csv=rowsForExport(rows).map(function(r){return r.map(csvEscape).join(',')}).join('\n'),a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8;'}));a.download=name;document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(a.href)}function render(){var size=parseInt(byId('pageSize').value,10),pages=Math.max(1,Math.ceil(filtered.length/size));if(currentPage>pages)currentPage=pages;var start=(currentPage-1)*size,rows=filtered.slice(start,start+size);byId('transactionBody').innerHTML=rows.map(function(r){return'<tr><td>'+r.date+'</td><td>'+r.id+'</td><td>'+r.description+'</td><td>'+r.category+'</td><td>'+money(r.amount)+'</td><td>'+r.type+'</td><td><span class="status-badge status-'+statusClass(r.status)+'"><i class="fa-solid fa-circle"></i>'+r.status+'</span></td></tr>'}).join('')||'<tr><td colspan="7" class="text-center text-muted fw-bold py-4">No transactions found.</td></tr>';byId('recordInfo').textContent='Showing '+(filtered.length?start+1:0)+' - '+Math.min(start+size,filtered.length)+' of '+filtered.length+' transactions';byId('pagination').innerHTML='<button class="page-btn" data-page="'+Math.max(1,currentPage-1)+'">Previous</button>'+Array.from({length:pages},function(_,i){return'<button class="page-btn '+(currentPage===i+1?'active':'')+'" data-page="'+(i+1)+'">'+(i+1)+'</button>'}).join('')+'<button class="page-btn" data-page="'+Math.min(pages,currentPage+1)+'">Next</button>'}function apply(){var date=byId('filterDate').value,cat=byId('filterCategory').value.toLowerCase().trim(),id=byId('filterTxn').value.toLowerCase().trim();filtered=txns.filter(function(r){return(!date||r.date===date)&&(!cat||r.category.toLowerCase().indexOf(cat)!==-1)&&(!id||r.id.toLowerCase().indexOf(id)!==-1)});currentPage=1;render()}function preview(){var title=byId('reportType').value+' - '+byId('categoryInput').value,total=filtered.reduce(function(s,r){return s+(r.type==='Credit'?Number(r.amount):-Number(r.amount))},0);byId('reportPreview').innerHTML='<div class="text-center mb-3"><img src="'+school.logo+'" style="width:72px;height:72px;object-fit:contain"><h3>'+school.name+'</h3><h5>'+title+'</h5><p>Session: '+byId('sessionInput').value+' | Term: '+byId('termInput').value+' | Generated: '+new Date().toLocaleDateString()+' | Generated By: '+accountant+'</p></div><div class="row g-3 mb-3"><div class="col-md-3"><strong>Total Revenue</strong><h5><?php echo frMoney($totalRevenue); ?></h5></div><div class="col-md-3"><strong>Total Expenses</strong><h5><?php echo frMoney($totalExpenses); ?></h5></div><div class="col-md-3"><strong>Net Income</strong><h5><?php echo frMoney($netIncome); ?></h5></div><div class="col-md-3"><strong>Grand Total</strong><h5>'+money(total)+'</h5></div></div><div class="table-responsive"><table class="table"><thead><tr><th>Date</th><th>Transaction ID</th><th>Description</th><th>Category</th><th>Amount</th><th>Type</th><th>Status</th></tr></thead><tbody>'+filtered.map(function(r){return'<tr><td>'+r.date+'</td><td>'+r.id+'</td><td>'+r.description+'</td><td>'+r.category+'</td><td>'+money(r.amount)+'</td><td>'+r.type+'</td><td>'+r.status+'</td></tr>'}).join('')+'</tbody></table></div>'}function printContent(html){var w=window.open('','_blank');w.document.write('<html><head><title>Financial Report</title><style>@page{size:A4 landscape;margin:12mm}body{font-family:Arial,sans-serif;color:#10201d}table{width:100%;border-collapse:collapse;font-size:11px}td,th{border:1px solid #777;padding:6px;text-align:left}th{background:#0f766e;color:#fff}.text-center{text-align:center}</style></head><body>'+html+'</body></html>');w.document.close();w.focus();w.print()}function printRows(rows){var body=rowsForExport(rows).slice(1).map(function(r){return'<tr>'+r.map(function(c){return'<td>'+c+'</td>'}).join('')+'</tr>'}).join('');printContent('<h2>Financial Reports</h2><table><thead><tr><th>Date</th><th>Transaction ID</th><th>Description</th><th>Category</th><th>Amount</th><th>Type</th><th>Status</th></tr></thead><tbody>'+body+'</tbody></table>')}document.addEventListener('DOMContentLoaded',render);byId('generateBtn').addEventListener('click',preview);byId('previewBtn').addEventListener('click',preview);byId('searchBtn').addEventListener('click',apply);byId('resetFilterBtn').addEventListener('click',function(){['filterDate','filterCategory','filterTxn'].forEach(function(id){byId(id).value=''});filtered=txns.slice();render()});byId('pageSize').addEventListener('change',function(){currentPage=1;render()});byId('pagination').addEventListener('click',function(e){if(e.target.classList.contains('page-btn')){currentPage=parseInt(e.target.dataset.page,10);render()}});byId('exportCsv').addEventListener('click',function(){downloadCsv(filtered,'Financial_Report.csv')});byId('exportExcel').addEventListener('click',function(){downloadCsv(filtered,'Financial_Report.xls')});byId('exportPdf').addEventListener('click',function(){printRows(filtered)});byId('printBtn').addEventListener('click',function(){printRows(filtered)});byId('previewPrint').addEventListener('click',function(){printContent(byId('reportPreview').innerHTML)});byId('previewExportPdf').addEventListener('click',function(){printContent(byId('reportPreview').innerHTML)});byId('previewExportExcel').addEventListener('click',function(){downloadCsv(filtered,'Preview_Financial_Report.xls')});
}());
</script>

